def maximumLength(self, s: str) -> int:
    n = len(s)
    max_length = 0
    for i in range(n):
        for j in range(i+1, n+1):
            count = 0
            for k in range(j, n+1):
                if s[i:k+1] == s[i:j+1]:
                    count += 1
                    if count >= 3:
                        max_length = max(max_length, count)
    return max_length

